import { GLScheduledTransaction } from './gl-scheduled-transaction.model';

export class GLEvent {
    glEventID : Number;
    leaseID : Number;
	startDate : Date;
	endDate : Date;
	frequency : String;
	amount : Number;
	currency : String;
	vendorId : string;
	vendor : String;
	status : String;
	category : string;
	accountName : String;
	accountCode : string;
	name : String;
	accountType : String;
	leaseName : string;
	portfolio : string;
	buildingName : string;
	address : string;
	city : string;
	state : string;
	country : string;
	transactions : GLScheduledTransaction[];

	constructor(glEventID,leaseID,startDate,endDate,frequency,amount,currency,vendorId,vendor,status,category, accountName, accountCode,name, accountType, leaseName, portfolio, buildingName, address, city, state, country, transactions) {
		this.glEventID = glEventID;
		this.leaseID = leaseID;
		this.startDate = startDate;
		this.endDate = endDate;
		this.frequency = frequency;
		this.amount = amount;
		this.currency = currency;
		this.vendorId = vendorId;
		this.vendor = vendor;
		this.status = status;
		this.category = category;
		this.accountName = accountName;
		this.accountCode = accountCode;
		this.name = name;
		this.accountType = accountType;
		this.leaseName = leaseName;
		this.portfolio = portfolio;
		this.buildingName = buildingName;
		this.address = address;
		this.city = city;
		this.state = state;
		this.country = country;
		this.transactions = transactions;
	}
}

